output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select the Pelvic Volume",
      "simple": "Choose the pelvic CT volume from the list.",
      "detailed": "This step identifies the patient's pelvic CT scan that will be used for fracture analysis and planning. Select the Pelvic Volume from the available volumes in the scene."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button to segment the bony pelvis.",
      "detailed": "This automated step segments the entire pelvic bone from the CT scan, creating a 3D model that will serve as the anatomical reference for fracture reduction and screw planning. Click the button and wait for the segmentation to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment the Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button to identify individual fracture fragments.",
      "detailed": "This step automatically separates the fractured pelvis into individual bone fragments. Each fragment represents a displaced piece that will be repositioned during reduction planning. Click the button to run the fracture segmentation."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fracture Fragments",
      "simple": "Untick any fracture fragments that should be excluded from the reduction plan.",
      "detailed": "Some small or non-displaced fragments may not need to be part of the reduction plan. Untick those segments to exclude them from the registration and template generation steps. Only fragments that require repositioning should remain ticked."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click 'Run Step 3: Generate Template' to create an alignment template for the fragments.",
      "detailed": "This step generates a statistical shape model or template that guides how the fracture fragments should be repositioned relative to the intact pelvis. It uses the intact hemipelvis as a reference to estimate the correct anatomical alignment."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fractures",
      "simple": "Click 'Run Step 4: Register _Reduce' to automatically align the fracture fragments.",
      "detailed": "This step performs automated registration of each fracture fragment to the template, effectively reducing the fracture by moving each piece back into its anatomical position. The result is a virtual reduction of the pelvis that approximates the pre-injury alignment."
    },
    {
      "step_id": "cb_step_7",
      "title": "Decide on Manual Adjustments",
      "simple": "Tick the 'Manually adjust a fragment' checkbox if you need to fine-tune any fragment position.",
      "detailed": "If the automated reduction did not fully restore proper alignment—for example, due to comminution or displacement—you may need to manually adjust individual fragments. If the reduction looks satisfactory, skip to step 11 to plan screws."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment you want to manually adjust from the 'Fragment' selection box.",
      "detailed": "Pick the specific fracture fragment that needs repositioning. The selection box lists all identified fragments. After selecting, you can adjust its position and rotation in the 3D view."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the transform tools to move and rotate the selected fragment into correct alignment.",
      "detailed": "Manually reposition the fragment to achieve an anatomical reduction. Use the 3D viewer controls to translate and rotate the fragment. This step is verified by visual inspection; when the fragment fits well against the adjacent bone surfaces, confirm with Done."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to finalize the manual repositioning.",
      "detailed": "This saves the manual transformation of the fragment and integrates it into the reduction plan. After applying, the fragment's new position is locked into the planning model."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Fixation",
      "simple": "Click 'Run Step 5: Plan Screws' to automatically suggest screw trajectories.",
      "detailed": "This step analyzes the reduced pelvis and fracture lines to propose optimal screw trajectories for fixation. The system generates candidate screw paths, typically in the form of cylindrical models or lines, that can be reviewed and adjusted."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide on Screw Trajectory Edits",
      "simple": "Tick the 'Edit Screw trajectories' checkbox if you need to modify the proposed screws.",
      "detailed": "If the automatically planned screw trajectories need adjustment—for example, to avoid a critical structure or to improve bone purchase—you can manually edit them. If the plan is satisfactory, no further action is needed."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform tools to adjust the position and orientation of each screw path.",
      "detailed": "Manipulate the screw trajectories to ensure they are safely within bone, avoid joint spaces, and provide adequate fixation. Verify each screw path in multiple views before confirming."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edited Trajectories",
      "simple": "Click 'Regenerate screws from edited lines' to update the screw models based on your manual edits.",
      "detailed": "After adjusting the trajectory lines, this step creates the final screw models (cylinders) that represent the planned implants. This ensures the edited paths are properly incorporated into the surgical plan."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finish Screw Editing",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to finalize the screw plan.",
      "detailed": "This exits the screw editing mode and confirms the current screw positions as final. The surgical plan for pelvic fracture reduction and screw fixation is now complete."
    }
  ]
}
